const fs = require('fs');

    //function to read and return the contents of the log file for the given file name
    const readFile = (fileName) => {
        return new Promise((resolve, reject) => {
            try{
                resolve(fs.readFileSync(fileName).toString());
            }catch (err){
                 reject(err);
            };
            
        });
    }